const lineId = 1;
const topicPrefix = "factory";
const tags = [
  { tag: "motor_rpm", base: 1750, noise: 45 },
  { tag: "line_pressure_bar", base: 6.2, noise: 0.25 },
  { tag: "temperature_c", base: 42, noise: 1.8 }
];
const t = tags[Math.floor(Math.random() * tags.length)];
const value = t.base + (Math.random() - 0.5) * 2 * t.noise;
const bad = Math.random() < 0.02;
const quality = bad ? 0 : 192;
msg.topic = `${topicPrefix}/line/${lineId}/telemetry`;
msg.payload = JSON.stringify({
  tag: t.tag,
  value: bad ? null : Math.round(value * 100) / 100,
  quality,
  source_ts: new Date().toISOString(),
  metadata: { source: "node-red-opc-sim", line: lineId }
});
return msg;

